#include<bits/stdc++.h>
using namespace std;

vector<int> a[100005];

int main()
{
	int n, q;
	cin >> n >> q;
	for(int x = 1; x <= q; x++)
	{
		int op, i, j, k;
		cin >> op >> i >> j;
		if(op == 1)
		{
			cin >> k;
			if(j + 1 > a[i].size()) a[i].resize(j + 1);
			a[i][j] = k;
		}
		else
			cout << a[i][j] << endl;
	}
}
